}
const express = require('express');
const filmRoutes = require('./src/film/film_routes');
const app = express();
const port = 3000;
app.listen(port, () =&gt; console.log(`app listening on port ${port}`)); app.use('/film', filmRoutes); app.get(`/`, (req, res) =&gt; { res.send('Hello World')
})
const pool = require('../../db');
const queries = require('./film_queries'); const getFilmList = (req, res) =&gt; { pool.query(queries.getFilmList, (error, results) =&gt; { if (error) throw error; res.status(200).json(results.rows); });
}; const getFilmById = (req, res) =&gt; { const id = parseInt(req.params.id); pool.query(queries.getFilmById, [id], (error, results) =&gt; { if (error) throw error; res.status(200).json(results.rows); });
} module.exports = { getFilmList, getFilmById,
};
const getFilmList = 'SELECT * FROM film';
const getFilmById = 'SELECT * FROM film WHERE id = $1'; module.exports = { getFilmList, getFilmById,
};
